  ('dietitian-moex-07014', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '有關瘦素（leptin）的敘述，下列何者錯誤？ 瘦素是白色脂肪組織所分泌 重度肥胖者體內有高濃度的瘦素 瘦素與位於中樞神經的受體結合後，刺激α -MSH（α -melanocyte-stimulating hormone）的釋放而抑制 食慾 飢餓狀態時瘦素濃度會上升', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07015', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '當飲食中醣類攝取不足時，胺基酸會經由異化作用產生下列何種物質？ 乙醇  酮體  膽鹼  草醋酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07016', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種荷爾蒙（hormone）會促進食慾？ leptin    cholecystokinin（CCK） ghrelin    peptide YY（PYY）', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07017', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '關於四氫葉酸（tetrahydrofolate）於細胞內之生化代謝功能，下列敘述何者正確？ 接受及轉移胺基（NH）與CO 結合形成尿素', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07018', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '2 接受及轉移氫質子還原呼吸電子傳遞鍊酵素複合體以利ATP生成 接受及轉移單碳以利胺基酸生合成 接受及轉移酮基以利葡萄糖生合成', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07019', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '維生素B 在食物中除了以游離態的型式存在外，主要是以下列何種輔酶的型式存在？ 2 核黃素單核苷酸（FMN）及硫胺雙磷酸（TDP） 核黃素單核苷酸（FMN）及核黃素腺嘌呤雙核苷酸（FAD） 核黃素腺嘌呤雙核苷酸（FAD）及黃素蛋白（flavoproteins） 核黃素腺嘌呤雙核苷酸（FAD）及核黃素激酶（flavokinase）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07020', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '晉小姐近日發現皮膚出現紅狀斑點、牙齦出血及小腿肌肉疼痛，可能與下列何種營養素缺乏有關？ 維生素A  維生素E  維生素D  維生素C', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
